import{_ as e,o as s,c as a,ai as l}from"./chunks/framework.CQB9ksOm.js";const r=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ch4/ch4_1.md","filePath":"ch4/ch4_1.md"}'),t={name:"ch4/ch4_1.md"};function n(h,i,d,o,c,k){return s(),a("div",null,[...i[0]||(i[0]=[l(`<h2 id="_4-1-dockerfile-简单使用" tabindex="-1">4.1 Dockerfile 简单使用 <a class="header-anchor" href="#_4-1-dockerfile-简单使用" aria-label="Permalink to “4.1 Dockerfile 简单使用”">​</a></h2><p>以 Web 开发为例，我们可以在官方 nginx 镜像基础上，添加自定义的网页文件、修改配置文件、安装必要的工具等。这样就能保证开发、测试和线上环境完全一致，不会因为环境不同出问题。</p><p>具体操作如下：</p><ol><li>创建一个新的空白目录 <code>myweb</code>。</li><li>在目录 <code>myweb</code> 下创建一个文本文件，命名为 <code>Dockerfile</code>，并在文件中添加如下内容。</li></ol><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">FROM</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RUN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;h1&gt;My Custom Nginx Page&lt;/h1&gt;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/nginx/html/index.html</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EXPOSE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span></span></code></pre></div><p>这个 Dockerfile 做了三件事：第一行 <code>FROM nginx:latest</code> 指定使用最新版 nginx 作为基础镜像；第二行 <code>RUN</code> 命令将网页内容放到容器的 nginx 默认的网页目录中；第三行 <code>EXPOSE 80</code> 声明容器会使用 <code>80</code> 端口。</p><ol start="3"><li>在 <code>myweb</code> 目录下运行命令 <code>docker build -t my-web .</code> 进行自定义 nginx 镜像构建。</li></ol><p>这样就完成了自定义 nginx 镜像的构建。其中 <code>-t my-web</code> 是给新镜像命名为 my-web，最后的点表示使用当前目录的 Dockerfile。</p><p>构建完成后可以用 <code>docker images</code> 查看新构建的镜像。</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;user-select:none;-webkit-user-select:none;">$ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> images</span></span></code></pre></div><ol start="4"><li>运行 <code>docker run -d -p 80:80 my-web</code> 启动容器。</li></ol><p>这时访问主机的 80 端口就能看到自定义网页了。</p>`,12)])])}const g=e(t,[["render",n]]);export{r as __pageData,g as default};
